import React, {
    useContext,
    useState
} from "react";

import {
    CartContext
} from "../contexts/CartContext";


function CheckoutPage() {

    const {

        totalPrice,

        clearCart

    } = useContext(
        CartContext
    );


    const [name, setName] =
        useState("");

    const [address, setAddress] =
        useState("");

    const [message, setMessage] =
        useState("");


    function handleSubmit(
        event
    ) {

        event.preventDefault();

        if (
            name === "" ||
            address === ""
        ) {

            setMessage(
                "Please fill all fields."
            );

            return;

        }

        setMessage(
            "Order placed successfully."
        );

        clearCart();

    }


    return (

        <div>

            <h1>

                Checkout

            </h1>

            <form
                onSubmit={
                    handleSubmit
                }
            >

                <input

                    type="text"

                    placeholder="Name"

                    value={name}

                    onChange={
                        event =>
                            setName(
                                event.target.value
                            )
                    }

                />

                <br />

                <input

                    type="text"

                    placeholder="Address"

                    value={address}

                    onChange={
                        event =>
                            setAddress(
                                event.target.value
                            )
                    }

                />

                <br />

                <h2>

                    Total Amount :

                    ${totalPrice.toFixed(2)}

                </h2>

                <button>

                    Place Order

                </button>

            </form>

            <h3>

                {message}

            </h3>

        </div>

    );

}

export default CheckoutPage;
